//
// Component: Info Box
//

.info-box {
  @include box-shadow($lte-card-shadow);
  @include border-radius($border-radius);

  position: relative;
  display: flex;
  width: 100%;
  min-height: 80px;
  padding: .5rem;
  margin-bottom: map-get($spacers, 3);
  color: var(--#{$prefix}body-color);
  background-color: var(--#{$prefix}body-bg);

  .progress {
    height: 2px;
    margin: 5px 0;
    background-color: rgba(var(--#{$lte-prefix}card-variant-color-rgb), .125);

    .progress-bar {
      background-color: var(--#{$lte-prefix}card-variant-color);
    }
  }

  .info-box-icon {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 70px;
    font-size: 1.875rem;
    text-align: center;
    @include border-radius($border-radius);

    > img {
      max-width: 100%;
    }
  }

  .info-box-content {
    display: flex;
    flex: 1;
    flex-direction: column;
    justify-content: center;
    padding: 0 10px;
    line-height: 1.8;
  }

  .info-box-number {
    display: block;
    margin-top: .25rem;
    font-weight: $font-weight-bold;
  }

  .progress-description,
  .info-box-text {
    display: block;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .info-box-more {
    display: block;
  }

  .progress-description {
    margin: 0;

  }

  @include media-breakpoint-up(md) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      .progress-description {
        display: none;
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      .progress-description {
        display: none;
      }
    }
  }

  @include media-breakpoint-up(lg) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      .progress-description {
        @include font-size(.75rem);
        display: block;
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      .progress-description {
        @include font-size(.75rem);
        display: block;
      }
    }
  }

  @include media-breakpoint-up(xl) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      .progress-description {
        @include font-size(1rem);
        display: block;
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      .progress-description {
        @include font-size(1rem);
        display: block;
      }
    }
  }
}

//
// Pages: Login & Register
//

.login-logo,
.register-logo {
  margin-bottom: .9rem;
  font-size: 2.1rem;
  font-weight: 300;
  text-align: center;

  a {
    color: var(--#{$prefix}secondary-color);
    text-decoration: none;
  }
}

.login-page,
.register-page {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
}

.login-box,
.register-box {
  width: 400px;

  @media (max-width: map-get($grid-breakpoints, sm)) {
    width: 90%;
    margin-top: .5rem;
  }

  .card {
    margin-bottom: 0;
  }
}

.login-card-body,
.register-card-body {
  padding: 20px;
  color: var(--#{$prefix}secondary-color);
  background-color: var(--#{$prefix}body-bg);
  border-top: 0;

  .input-group {
    .form-control {
      &:focus {
        box-shadow: none;

        ~ .input-group-prepend .input-group-text,
        ~ .input-group-append .input-group-text {
          border-color: $input-focus-border-color;
        }
      }

      &.is-valid {
        &:focus {
          box-shadow: none;
        }

        ~ .input-group-prepend .input-group-text,
        ~ .input-group-append .input-group-text {
          border-color: $success;
        }
      }

      &.is-invalid {
        &:focus {
          box-shadow: none;
        }

        ~ .input-group-append .input-group-text {
          border-color: $danger;
        }
      }
    }

    .input-group-text {
      color: var(--#{$prefix}secondary-color);
      background-color: transparent;
      @include border-top-end-radius($border-radius);
      @include border-bottom-end-radius($border-radius);
      @include transition($input-transition);
    }
  }
}

.login-box-msg,
.register-box-msg {
  padding: 0 20px 20px;
  margin: 0;
  text-align: center;
}

.social-auth-links {
  margin: 10px 0;
}

@use "sass:color";

.welcome-accordion {
  margin-top: 3rem;
  margin-bottom: 3rem;
}

.welcome-accordion-item {

  &.is-active {
    // box-shadow: 0px 1px 8px 0px rgba(0,0,0,0.15);

    .accordion-title {
      margin-bottom: 0;
      border-bottom: none;
      color: $black;
      border: none;
      padding-left: 1rem;
    }

    .accordion-content {
      // margin-bottom: 1rem;
      border: none;
      border-bottom: 1px dashed #e6e6e6;
    }
  }

  .accordion-title:focus,
  .accordion-title:active {
    background: none;
  }

  .accordion-title {
    color: color.adjust($dark-gray, $lightness: -10%);
    font-size: 1.25rem;
    line-height: 1.5;
    padding-left: 0;
    background: none;
    border: none;
    border-bottom: 1px dashed #d6d6d6;
    transition: all 0.3s ease;
  }

  .accordion-title:hover {
    padding-left: 1rem;
    color: $black;
    transition: all 0.3s ease;
  }

  .accordion-title::before {
    color: $dark-gray;
    font-size: 1.25rem;
    line-height: 1;
    top: 45%;
    border-radius: 50%;
    border: 1px solid $light-gray;
    background-color: $white;
    width: 25px;
    height: 25px;
    text-align: center;
    transition: all 0.3s ease;
  }

  .accordion-title:hover::before {
    color: $black;
    background-color: color.adjust($light-gray, $lightness: 8%);
    border: 1px solid $medium-gray;
    transition: all 0.3s ease;
  }
}

.welcome-accordion-item:last-child {

  .accordion-title{
    border-bottom: none;
  }
}

.accordion-content-item {
  font-family: Helvetica, Arial, sans-serif;
  margin-bottom: 2rem;
}

.docs-component .accordion-content-item-divider {
  border-bottom: 1px dashed #e5e5e5;
  margin-bottom: 0;
}

.accordion-content-item-thumbnail {

  img {
    border: 1px solid $light-gray;
  }

  @include breakpoint(small down) {
    margin-bottom: 1rem;
  }
}

.accordion-content-item-cta {

  img {
    margin-right: 0.5rem;
  }
}

// Prevent FOUC on nav accordion
.accordion-content.is-active {
  display: block;
}

.responsive-embed {
  margin-bottom: 0;
}

@import "./breadcrumb";
@import "./breadcrumb.md.vars";

// Breadcrumb
// --------------------------------------------------

:host {
  --color: #{$breadcrumb-md-color};
  --color-active: #{$breadcrumb-md-color-active};
  --color-hover: #{$breadcrumb-md-color-active};
  --color-focused: #{$breadcrumb-md-color-focused};
  --background-focused: #{$breadcrumb-md-background-focused};
}

:host(.breadcrumb-active) {
  font-weight: 500;
}

.breadcrumb-native {
  @include padding(6px, 12px, 6px, 12px);
}


// Breadcrumb Separator
// ------------------------------------------

.breadcrumb-separator {
  @include margin($breadcrumb-md-separator-margin-top, $breadcrumb-md-separator-margin-end, $breadcrumb-md-separator-margin-bottom, $breadcrumb-md-separator-margin-start);
}


// Breadcrumb: Focused
// ------------------------------------------

:host(.ion-focused) .breadcrumb-native {
  @include border-radius(4px);

  box-shadow: 0px 1px 2px rgba(0, 0, 0, 0.2), 0px 2px 8px rgba(0, 0, 0, 0.12);
}


// Breadcrumb Separator
// ------------------------------------------

.breadcrumb-separator {
  color: $breadcrumb-md-separator-color;
}


// Breadcrumb Slotted Icons
// ------------------------------------------

::slotted(ion-icon) {
  color: $breadcrumb-md-icon-color;

  font-size: dynamic-font(18px);
}

::slotted(ion-icon[slot="start"]) {
  @include margin(null, 8px, null, null);
}

::slotted(ion-icon[slot="end"]) {
  @include margin(null, null, null, 8px);
}

:host(.breadcrumb-active) ::slotted(ion-icon) {
  color: $breadcrumb-md-icon-color-active;
}


// Breadcrumbs Collapsed Indicator
// --------------------------------------------------

.breadcrumbs-collapsed-indicator {
  @include border-radius(2px);

  background: $breadcrumb-md-indicator-background;

  color: $breadcrumb-md-indicator-color;
}

.breadcrumbs-collapsed-indicator:hover {
  opacity: 0.7;
}

.breadcrumbs-collapsed-indicator:focus {
  background: $breadcrumb-md-indicator-background-focused;
}

@import "./picker";
@import "./picker.ios.vars";

// iOS Picker
// --------------------------------------------------

:host {
  --background: #{$picker-ios-background-color};
  --border-width: #{1px 0 0};
  --border-color: #{$picker-ios-border-color};
  --height: #{$picker-ios-height};
  --backdrop-opacity: var(--ion-backdrop-opacity, 0.26);

  color: $picker-ios-option-text-color;
}

.picker-toolbar {
  display: flex;

  height: $picker-ios-toolbar-height;

  border-bottom: $hairlines-width solid var(--border-color);
}

.picker-toolbar-button {
  flex: 1;

  text-align: end;
}

.picker-toolbar-button:last-child .picker-button {
  font-weight: $picker-ios-button-strong-font-weight;
}

.picker-toolbar-button:first-child {
  font-weight: normal;

  text-align: start;
}

.picker-button,
.picker-button.ion-activated {
  @include margin(0);
  @include padding($picker-ios-button-padding-top, $picker-ios-button-padding-end, $picker-ios-button-padding-bottom, $picker-ios-button-padding-start);

  height: $picker-ios-button-height;

  background: transparent;
  color: $picker-ios-button-text-color;

  font-size: $picker-ios-button-font-size;
}

.picker-columns {
  height: $picker-ios-height - $picker-ios-toolbar-height - 1;
  perspective: $picker-ios-column-perspective;
}

.picker-above-highlight {
  @include position(0, null, null, 0);
  @include transform(translate3d(0, 0, 90px));

  display: block;
  position: absolute;

  width: 100%;
  height: $picker-ios-option-offset-y + 4px;

  border-bottom: 1px solid var(--border-color);

  background: linear-gradient(
    to bottom,
    $picker-ios-top-background-color 20%,
    $picker-ios-bottom-background-color 100%);

  z-index: 10;
}

.picker-below-highlight {
  @include position($picker-ios-option-offset-y + $picker-ios-option-height - 4, null, null, 0);
  @include transform(translate3d(0, 0, 90px));

  display: block;
  position: absolute;

  width: 100%;
  height: $picker-ios-option-offset-y + $picker-ios-option-height;

  border-top: 1px solid var(--border-color);

  background: linear-gradient(
    to top,
    $picker-ios-top-background-color 30%,
    $picker-ios-bottom-background-color 100%);

  z-index: 11;
}

@use '../../sass/variables' as *;

select.browser-default {
  opacity: 1;
  color: var(--md-sys-color-on-background);
}

// TODO: Change to ".select" and not use tag name directly
// Keep selects useable without javascript

select {
  background-color: var(--md-sys-color-surface);
  width: 100%;
  padding: 5px;
  border: 1px solid var(--md-sys-color-outline-variant);
  border-radius: 2px;
  height: 3rem;
}

.select-wrapper:focus-within {
  outline: 2px solid var(--md-sys-color-primary);
  border-radius: 4px;
}

.select-wrapper {
  position: relative;

  .caret {
    position: absolute;
    right: 0;
    top: 0;
    bottom: 0;
    margin: auto 0;
    z-index: 0;
    fill: var(--md-sys-color-on-background);
    pointer-events: none;
  }

  // Hide select with overflow hidden instead of using display none
  // (this prevents form validation errors with hidden form elements)
  .hide-select {
    width: 0;
    height: 0;
    overflow: hidden;
    position: absolute;
    top: 0;
    z-index: -1;
  }
}

select:disabled {
  color: var(--md-sys-color-on-surface);
}

.select-wrapper.disabled {
  + label {
    color: var(--md-sys-color-on-surface);
  }
  .caret {
    fill: var(--md-sys-color-on-surface);
  }
}

.select-wrapper input.select-dropdown:disabled {
  color: var(--md-sys-color-on-surface);
  cursor: default;
  user-select: none;
}

.select-wrapper i {
  color: var(--md-sys-color-on-surface);
}

.select-dropdown li.disabled,
.select-dropdown li.disabled > span,
.select-dropdown li.optgroup {
  color: var(--md-sys-color-on-surface);
  //background-color: transparent;
}

// Icons
.select-dropdown li {
  img {
    height: $dropdown-item-height - 10;
    width: $dropdown-item-height - 10;
    margin: 5px 15px;
    object-fit: cover;
    float: right;
  }
}

// Optgroup styles
.select-dropdown li.optgroup {
  border-top: 1px solid rgba(0, 0, 0, 0.04);
  &.selected > span {
    color: var(--md-sys-color-on-background);
  }
  & > span {
    color: var(--md-sys-color-on-surface-variant);
  }
  & ~ li.optgroup-option {
    padding-left: 1rem;
  }
}

// Image comparison slider
// Credit: http://codepen.io/solipsistacp/pen/Gpmaq
.comparison-slider {
  height: 50vh;
  overflow: hidden;
  position: relative;
  width: 100%;
  -webkit-overflow-scrolling: touch;

  .comparison-before,
  .comparison-after {
    height: 100%;
    left: 0;
    margin: 0;
    overflow: hidden;
    position: absolute;
    top: 0;

    img {
      height: 100%;
      object-fit: cover;
      object-position: left center;
      position: absolute;
      width: 100%;
    }
  }

  .comparison-before {
    width: 100%;
    z-index: 1;

    .comparison-label {
      right: $unit-4;
    }
  }

  .comparison-after {
    max-width: 100%;
    min-width: 0;
    z-index: 2;

    &::before {
      background: transparent;
      content: "";
      cursor: default;
      height: 100%;
      left: 0;
      position: absolute;
      right: $unit-4;
      top: 0;
      z-index: $zindex-0;
    }

    &::after {
      background: currentColor;
      border-radius: 50%;
      box-shadow: 0 -5px, 0 5px;
      color: $light-color;
      content: "";
      height: 3px;
      pointer-events: none;
      position: absolute;
      right: $unit-2;
      top: 50%;
      transform: translate(50%, -50%);
      width: 3px;
    }

    .comparison-label {
      left: $unit-4;
    }
  }

  .comparison-resizer {
    animation: first-run 1.5s 1 ease-in-out;
    cursor: ew-resize;
    height: $unit-4;
    left: 0;
    max-width: 100%;
    min-width: $unit-4;
    opacity: 0;
    outline: none;
    position: relative;
    resize: horizontal;
    top: 50%;
    transform: translateY(-50%) scaleY(30);
    width: 0;
  }

  .comparison-label {
    background: rgba($dark-color, .5);
    bottom: $unit-4;
    color: $light-color;
    padding: $unit-1 $unit-2;
    position: absolute;
    user-select: none;
  }
}

@keyframes first-run {
  0% {
    width: 0;
  }
  25% {
    width: $unit-12;
  }
  50% {
    width: $unit-4;
  }
  75% {
    width: $unit-6;
  }
  100% {
    width: 0;
  }
}

// Icon arrows
.icon-arrow-down,
.icon-arrow-left,
.icon-arrow-right,
.icon-arrow-up,
.icon-downward,
.icon-back,
.icon-forward,
.icon-upward {
  &::before {
    border: $icon-border-width solid currentColor;
    border-bottom: 0;
    border-right: 0;
    height: .65em;
    width: .65em;
  }
}

.icon-arrow-down {
  &::before {
    transform: translate(-50%, -75%) rotate(225deg);
  }
}

.icon-arrow-left {
  &::before {
    transform: translate(-25%, -50%) rotate(-45deg);
  }
}

.icon-arrow-right {
  &::before {
    transform: translate(-75%, -50%) rotate(135deg);
  }
}

.icon-arrow-up {
  &::before {
    transform: translate(-50%, -25%) rotate(45deg);
  }
}

.icon-back,
.icon-forward {
  &::after {
    background: currentColor;
    height: $icon-border-width;
    width: .8em;
  }
}

.icon-downward,
.icon-upward {
  &::after {
    background: currentColor;
    height: .8em;
    width: $icon-border-width;
  }
}

.icon-back {
  &::after {
    left: 55%;
  }
  &::before {
    transform: translate(-50%, -50%) rotate(-45deg);
  }
}

.icon-downward {
  &::after {
    top: 45%;
  }
  &::before {
    transform: translate(-50%, -50%) rotate(-135deg);
  }
}

.icon-forward {
  &::after {
    left: 45%;
  }
  &::before {
    transform: translate(-50%, -50%) rotate(135deg);
  }
}

.icon-upward {
  &::after {
    top: 55%;
  }
  &::before {
    transform: translate(-50%, -50%) rotate(45deg);
  }
}

// Icon caret
.icon-caret {
  &::before {
    border-top: .3em solid currentColor;
    border-right: .3em solid transparent;
    border-left: .3em solid transparent;
    height: 0;
    transform: translate(-50%, -25%);
    width: 0;
  }
}

// Icon menu
.icon-menu {
  &::before {
    background: currentColor;
    box-shadow: 0 -.35em, 0 .35em;
    height: $icon-border-width;
    width: 100%;
  }
}

// Icon apps
.icon-apps {
  &::before {
    background: currentColor;
    box-shadow: -.35em -.35em, -.35em 0, -.35em .35em, 0 -.35em, 0 .35em, .35em -.35em, .35em 0, .35em .35em;
    height: 3px;
    width: 3px;
  }
}

// Button group
//
// A button group is a series of buttons laid out next to each other, all part
// of one visual button, but separated by rules to be separate.

.BtnGroup {
  display: inline-block;
  vertical-align: middle;

  @include clearfix();

  // Proper spacing for multiple button groups (a la, gollum editor)
  + .BtnGroup,
  + .btn {
    margin-left: var(--base-size-4);
  }
}

.BtnGroup-item {
  position: relative;
  float: left;
  border-right-width: 0;
  border-radius: 0;

  &:first-child {
    // stylelint-disable-next-line primer/borders
    border-top-left-radius: $border-radius;
    // stylelint-disable-next-line primer/borders
    border-bottom-left-radius: $border-radius;
  }

  &:last-child {
    // stylelint-disable-next-line primer/borders
    border-right-width: $border-width;
    // stylelint-disable-next-line primer/borders
    border-top-right-radius: $border-radius;
    // stylelint-disable-next-line primer/borders
    border-bottom-right-radius: $border-radius;
  }

  &.selected,
  &[aria-selected='true'],
  &:focus,
  &:active,
  &:hover {
    // stylelint-disable-next-line primer/borders
    border-right-width: $border-width;

    + .BtnGroup-item,
    + .BtnGroup-parent .BtnGroup-item {
      border-left-width: 0;
    }
  }
}

.BtnGroup-parent {
  float: left;

  &:first-child .BtnGroup-item {
    // stylelint-disable-next-line primer/borders
    border-top-left-radius: $border-radius;
    // stylelint-disable-next-line primer/borders
    border-bottom-left-radius: $border-radius;
  }

  &:last-child .BtnGroup-item {
    // stylelint-disable-next-line primer/borders
    border-right-width: $border-width;
    // stylelint-disable-next-line primer/borders
    border-top-right-radius: $border-radius;
    // stylelint-disable-next-line primer/borders
    border-bottom-right-radius: $border-radius;
  }

  .BtnGroup-item {
