    width: units($collection-thumb-width);
  }
}

.usa-collection__body {
  @include u-flex(1);
}

.usa-collection__heading {
  @include typeset($theme-collection-header-typeset);
  @include u-margin-bottom(0);
  @include u-margin-top(0);
}

.usa-collection__description {
  @include u-margin-y(1);
}

.usa-collection__meta {
  @include unstyled-list;
  @include u-margin-top(0.5);
}

.usa-collection__meta-item {
  @include u-margin-top(0.5);
  @include typeset("ui", "2xs", 3);
  display: block;
  margin-right: units(1);

  &.usa-tag {
    @include u-bg("base-lighter");
    @include u-line-height("ui", 1);
    @include u-padding-y(0.5);
    @include u-text("ink");
    display: inline-block;
    margin-top: units(0.5);

    &--new {
      @include u-bg("accent-warm-dark");
      @include u-text("white");
    }
  }
}

.usa-collection__calendar-date {
  text-decoration: none;
}

.usa-collection__calendar-date-month,
.usa-collection__calendar-date-day {
  @include u-font("ui", 6);
  display: block;
  font-weight: fw("bold");
  padding: units(0.5);
  text-align: center;

  @include at-media("tablet") {
    padding: units(1);
  }
}

.usa-collection__calendar-date-month {
  @include u-radius-top("sm");
  background-color: color("primary");
  color: color("white");
}

.usa-collection__calendar-date-day {
  @include u-radius-bottom("sm");
  border: 1px solid color("primary");
  color: color("primary");
}

.usa-collection--condensed {
  .usa-collection__item {
    @include u-margin-y(1);
    @include u-padding-top(1);
  }
}

@use "uswds-core" as *;

.usa-language {
  @include u-flex("row", "align-center", "justify-end");
  display: flex;
  padding: 0 0 units(0.5) units(1);
  width: 100%;

  &--small {
    .usa-button {
      @include u-padding-x(1.5);
      @include u-padding-y(0);
      font-size: font-size($theme-header-font-family, "3xs");
      height: units(4);
      margin-top: 0.3rem;
      min-width: units($theme-button-small-width);
    }
  }
}

.usa-language-container {
  @include u-flex("align-center", "justify-end");
  display: flex;
}

.usa-nav-container {
  .usa-language-container {
    align-self: center;
    margin-left: units(0);
    position: absolute;
    right: units(10);
    top: units(2);

    @include at-media($theme-header-min-width) {
      align-self: flex-end;
      margin-left: units(1.5);
      margin-bottom: units(1);
      position: relative;
      right: inherit;
      top: units(-2px);
    }
  }
}

.usa-language__link {
  margin-right: units(0);
}

.usa-language__primary {
  width: auto;
}

.usa-language__primary-item:last-of-type {
  position: relative;

  .usa-language__submenu {
    @include u-pin-right;
  }
}

.usa-language__submenu {
  @include add-list-reset;
  @include nav-sublist;
  background-color: color("primary-darker");
  position: absolute;
  width: units("card-lg");
  z-index: z-index(400);

  &[aria-hidden="true"] {
    display: none;
  }

  .usa-language__submenu-item {
    a {
      color: color("white");
      display: block;
      line-height: line-height($theme-navigation-font-family, 3);
      padding: 0;
      padding: units(1);
      text-decoration: none;

      &:focus {
        outline-offset: units("neg-05");
      }

      &:hover {
        color: color("white");
        text-decoration: underline;
      }
    }
  }
}

.usa-language__submenu-list {
  @include unstyled-list;

  .usa-language__submenu-list-item {
    margin: 0;
    font-size: font-size($theme-navigation-font-family, "2xs");

    a {
      line-height: line-height($theme-navigation-font-family, 3);
    }
  }
}

@use "./add-bar" as *;
@use "../../functions" as *;
@use "../../mixins/helpers" as *;
@use "../../mixins/typography/unstyled-list" as *;
@use "../../mixins/utilities" as *;
@use "../../settings" as *;

$sidenav-level-1-inset: 2;
$sidenav-level-2-inset: 4;
$sidenav-level-3-inset: 6;
$sidenav-level-4-inset: 8;

@mixin nav-list($type) {
  @include unstyled-list();

  @if $type == "sidenav" {
    &__item {
      border-top: units(1px) solid color("base-lighter");
    }
  }

  @if $type == "nav" {
    &-item {
      border-top: units(1px) solid color("base-lighter");
    }
  }

  a:not(.usa-button) {
    display: block;
    padding: units(1) units($sidenav-level-1-inset);
    text-decoration: none;

    &:hover {
      background-color: color("base-lightest");
      text-decoration: none;
    }
  }

  a:not(.usa-button):not(.usa-current) {
    color: color("base-dark");

    &:hover {
      color: color($theme-link-color);
    }

    &:focus {
      outline-offset: 0;
    }
  }

  .usa-current {
    @include add-bar(
      $theme-sidenav-current-border-width,
      "primary",
      "left",
      "pill",
      0.5,
      0.5
    );
    color: color($theme-link-color);
    font-weight: font-weight("bold");

    @include at-media("tablet") {
      @include add-bar(
        $theme-sidenav-current-border-width,
        $theme-link-color,
        "left",
        "pill",
        0,
        0.5
      );
    }
  }
}

@mixin nav-sublist {
  @include unstyled-list();
  margin: 0;

  &-item {
    border-top: units(1px) solid color("base-lighter");
    font-size: font-size($theme-sidenav-font-family, "2xs");
  }

  .usa-current {
    @include remove-bar;

    @include at-media("tablet") {
      @include remove-bar;
    }
  }

  // level 2+
  a:not(.usa-button) {
    padding-left: units($sidenav-level-2-inset);
  }

  // level 3+
  & & a:not(.usa-button) {
    padding-left: units($sidenav-level-3-inset);
  }

  // level 4+
  & & & a:not(.usa-button) {
    padding-left: units($sidenav-level-4-inset);
  }
}
